document.addEventListener("DOMContentLoaded",(function(){window.formatISODate=function formatISODate(t){if(null==t)return"";if(t instanceof Date&&!isNaN(t))return t.toISOString().slice(0,10);const e=String(t).trim();if(!e)return"";if(/^\d+$/.test(e)){const t=Number(e.length<=10?1e3*Number(e):Number(e)),n=new Date(t);return isNaN(n)?"":n.toISOString().slice(0,10)}let n=e.match(/^(\d{4})[-\/.](\d{1,2})[-\/.](\d{1,2})$/);if(n){const[,t,e,r]=n.map(Number),i=new Date(Date.UTC(t,e-1,r));return isNaN(i)?"":i.toISOString().slice(0,10)}if(n=e.match(/^(\d{1,2})[-\/.](\d{1,2})[-\/.](\d{4})$/),n){const[,t,e,r]=n.map(Number),i=new Date(Date.UTC(r,e-1,t));return isNaN(i)?"":i.toISOString().slice(0,10)}const r=new Date(e);return isNaN(r)?"":r.toISOString().slice(0,10)}}));